import{_ as a,c as o,a3 as t,o as i}from"./chunks/framework.BDUoXecB.js";const p=JSON.parse('{"title":"Web API 設計標準","description":"","frontmatter":{},"headers":[],"relativePath":"documents/forOpenAPISpecification/API_Design.md","filePath":"documents/forOpenAPISpecification/API_Design.md"}'),l={name:"documents/forOpenAPISpecification/API_Design.md"};function r(d,e,c,n,h,s){return i(),o("div",null,e[0]||(e[0]=[t('<h1 id="web-api-設計標準" tabindex="-1">Web API 設計標準 <a class="header-anchor" href="#web-api-設計標準" aria-label="Permalink to &quot;Web API 設計標準&quot;">​</a></h1><p>OpenAPI Specification 規約を利用するに当たり、想定する Web API の設計ルールをまとめる。このルールに必ずしも準じる必要は無いが、このような設計を暗黙的に考慮し OpenAPI Specification 規約を作成している。</p><h2 id="http-メソッド" tabindex="-1">HTTP メソッド <a class="header-anchor" href="#http-メソッド" aria-label="Permalink to &quot;HTTP メソッド&quot;">​</a></h2><p>実現したい操作により、以下のような使い分けを想定する。HEAD（リソースの存在チェック）、GET（参照）、POST（新規作成）、PUT（更新）、PATCH（一部更新）、DELETE（削除）。</p><h2 id="http-ステータス" tabindex="-1">HTTP ステータス <a class="header-anchor" href="#http-ステータス" aria-label="Permalink to &quot;HTTP ステータス&quot;">​</a></h2><p><a href="https://tools.ietf.org/html/rfc7231#section-6" target="_blank" rel="noreferrer">RFC 7231</a>で定義されているレスポンスステータスコードを利用します。</p><p><a href="https://datatracker.ietf.org/doc/html/rfc9205" target="_blank" rel="noreferrer">RFC9205</a>（<a href="https://tex2e.github.io/rfc-translater/html/rfc9205.html#section-4.6" target="_blank" rel="noreferrer">日本語訳</a>）の方針に原則則る。ユースケース別に利用すべき HTTP ステータスコードを記載します。</p><h3 id="共通" tabindex="-1">共通 <a class="header-anchor" href="#共通" aria-label="Permalink to &quot;共通&quot;">​</a></h3><ul><li>バリデーションエラー：<code>400 Bad Request</code></li><li>業務エラー：<code>400 Bad Request</code></li><li>認証エラー：<code>401 Unauthorized</code></li><li>認可エラー：<code>403 Forbidden</code></li><li>システムエラー：<code>500 Internal Server Error</code></li></ul><h3 id="get" tabindex="-1">GET <a class="header-anchor" href="#get" aria-label="Permalink to &quot;GET&quot;">​</a></h3><ul><li>正常系：<code>200 OK</code><ul><li>検索系 API で結果 0 件の場合も、 <code>200 OK</code> を返すとする</li></ul></li><li>パスキー検索系 API で対象リソースが存在しないエラー：<code>404 Not Found</code></li></ul><h3 id="post" tabindex="-1">POST <a class="header-anchor" href="#post" aria-label="Permalink to &quot;POST&quot;">​</a></h3><ul><li>正常系（同期）：<code>201 Created</code></li><li>正常系（非同期）：<code>202 Accepted</code></li><li>一意制約違反エラー：<code>409 Conflict</code></li><li>親リソースが存在しないエラー：<code>404 Not Found</code></li></ul><h3 id="put" tabindex="-1">PUT <a class="header-anchor" href="#put" aria-label="Permalink to &quot;PUT&quot;">​</a></h3><ul><li>正常系（同期）：<code>200 OK</code></li><li>正常系（非同期）：<code>202 Accepted</code></li><li>対象リソースが存在しないエラー：<code>404 Not Found</code></li></ul><h3 id="delete" tabindex="-1">DELETE <a class="header-anchor" href="#delete" aria-label="Permalink to &quot;DELETE&quot;">​</a></h3><ul><li>正常系：<code>204 No Content</code><ul><li>もし、削除した項目の情報を応答する場合は <code>200 OK</code> とする</li></ul></li><li>対象リソースが存在しないエラー：<code>404 Not Found</code></li></ul><h2 id="api-バージョン管理" tabindex="-1">API バージョン管理 <a class="header-anchor" href="#api-バージョン管理" aria-label="Permalink to &quot;API バージョン管理&quot;">​</a></h2><ul><li>/v1, /v2 といったパスで表現する</li><li>型名変更、必須パラメータの追加、レスポンスの桁数変更、などをするときはバージョンを上げることを検討する</li></ul><h2 id="パラメータの命名" tabindex="-1">パラメータの命名 <a class="header-anchor" href="#パラメータの命名" aria-label="Permalink to &quot;パラメータの命名&quot;">​</a></h2><p>boolean 型である場合、 <code>[a-zA-Z0-9-_]+_flag</code> という命名は非推奨とする。</p><p><code>is_[a-zA-Z0-9-_]+</code> や <code>has_[a-zA-Z0-9-_]+</code> などの命名を代わりに検討する</p>',22)]))}const P=a(l,[["render",r]]);export{p as __pageData,P as default};
